                ctx.fillRect(this.exit.x * sz, this.exit.y * sz, sz, sz);
                ctx.fillStyle = "rgba(0, 100, 255, 0.2)"; // Spawn area
                ctx.fillRect(this.spawn.x * sz, this.spawn.y * sz, sz, sz);

                // Draw Bots
                this.bots.forEach((bot, i) => {
